SELECT grouping(s.event_month) * $1 + grouping(s.lag_day) * $2 + grouping(s.load_epoch_day) * $3 + $4 + $5 AS grouping_id, s.event_month AS event_month, s.lag_day AS lag_day, s.load_epoch_day AS load_epoch_day, max(s.batch_id) AS batch_id, max(s.alt_value) AS alt_value, coalesce(sum(s.is_probe_row), $6) AS row_count, coalesce(sum(s.is_eligible), $7) AS n_curve_eligible, coalesce(sum(s.is_null_event_time), $8) AS n_null_event_time, coalesce(sum(s.is_null_load_time_only), $9) AS n_null_load_time_only, coalesce(sum(s.is_negative_clipped), $10) AS n_negative_clipped, coalesce(sum(s.is_negative_lag_excluded), $11) AS n_negative_lag_excluded, coalesce(sum(s.is_overflow), $12) AS n_overflow, coalesce(sum(s.is_join_unmatched), $13) AS n_join_unmatched, CAST($14 AS BIGINT) AS n_other_exclusions, coalesce(sum(s.is_base_row), $15) AS n_base_rows, coalesce(sum(s.is_ambiguous_base), $16) AS n_ambiguous_base_rows, coalesce(sum(s.is_compare_mismatch), $17) AS n_compare_mismatch, max(s.lookup_dup) AS max_lookup_dup, count(*) AS n_staged_rows, CAST(NULL AS BIGINT) AS distinct_keys, min(s.load_time) AS min_load_time 
FROM (SELECT CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= $18 OR demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < $19) THEN CAST(date_trunc('month', demo_retail.dbo.orders.order_date) AS DATE) ELSE NULL END AS event_month, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < $19) THEN $20 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= $18 AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) > $21) THEN $22 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= $18 AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < $23) THEN $24 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= $18) THEN date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) ELSE NULL END AS lag_day, CAST(demo_retail.dbo.orders.loaded_at AS DATE) AS load_epoch_day, CAST(NULL AS VARCHAR) AS batch_id, CAST(NULL AS VARCHAR) AS alt_value, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= $18) THEN $25 ELSE $26 END AS is_eligible, CASE WHEN (demo_retail.dbo.orders.order_date IS NULL) THEN $27 ELSE $28 END AS is_null_event_time, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NULL) THEN $29 ELSE $30 END AS is_null_load_time_only, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= $31 AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < $32) THEN $33 ELSE $34 END AS is_negative_clipped, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < $19) THEN $35 ELSE $36 END AS is_negative_lag_excluded, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= $18 AND date_diff('day', demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) > $37) THEN $38 ELSE $39 END AS is_overflow, CAST($40 AS INTEGER) AS is_join_unmatched, CAST($41 AS INTEGER) AS is_base_row, CAST($42 AS INTEGER) AS is_ambiguous_base, CAST($43 AS INTEGER) AS is_compare_mismatch, CAST($44 AS INTEGER) AS is_probe_row, CAST(NULL AS INTEGER) AS lookup_dup, CAST(NULL AS VARCHAR) AS key_hash, demo_retail.dbo.orders.loaded_at AS load_time 
FROM demo_retail.dbo.orders 
WHERE demo_retail.dbo.orders.loaded_at <= $45 OR demo_retail.dbo.orders.loaded_at IS NULL) AS s GROUP BY GROUPING SETS ((s.event_month, s.lag_day), (s.load_epoch_day)) 
 LIMIT $46
